await page.waitForFunction(() => {
  return document.body.innerText.includes("回答重点");
}, { timeout: 15000 });
```

然后从正文区域读，而不是从 `tabpanel` 读：

```js
const answer = await page.evaluate(() => {
  const clean = (s) => (s || "").replace(/\s+/g, " ").trim();

  const main = document.querySelector("main main") || document.querySelector("main");
  if (!main) return "";

  const text = clean(main.innerText);

  const start = text.indexOf("回答重点");
  if (start === -1) return "";

  const endCandidates = [
    text.indexOf("作者：", start),
    text.indexOf("分享最高赚", start),
    text.indexOf("上一题", start),
    text.indexOf("回答讨论", start),
  ].filter((i) => i > start);

  const end = endCandidates.length ? Math.min(...endCandidates) : text.length;

  return text.slice(start, end).trim();
});
```

